test.create_query:
CREATE TABLE inverse_lookup_source_table
(
    id UInt64,
    attr_string String,
    attr_uint UInt64
) ENGINE = MergeTree ORDER BY id;

CREATE TABLE inverse_lookup_fact_table
(
    key UInt64,
    payload String
) ENGINE = MergeTree ORDER BY key;

CREATE TABLE composite_key_fact_table
(
    key1 UInt64,
    key2 String,
    payload String
) ENGINE = MergeTree ORDER BY (key1, key2);

test.fill_query:
INSERT INTO inverse_lookup_source_table
SELECT number, toString(number % 10), number % 10
FROM numbers(1000000);

INSERT INTO inverse_lookup_fact_table
SELECT rand64() % 10, toString(number % 10)
FROM numbers(5000000);

INSERT INTO composite_key_source_table
SELECT number % 100, toString(number % 10), toString(number % 10), number % 10
FROM numbers(1000000);

INSERT INTO composite_key_fact_table
SELECT rand64() % 100, toString(rand64() % 10), toString(number % 10)
FROM numbers(5000000);
